package com.lkl.studygroup.config; import org.springframework.boot.CommandLineRunner; import org.springframework.context.annotation.Bean; import org.springframework.context.annotation.Configuration; @Configuration public class EnvCheckConfig { @Bean public CommandLineRunner printEnv() { return args -> { System.out.println("====== ENVIRONMENT VARIABLES DUMP ======"); System.out.println("DB_POSTGRES_URL: " + System.getenv("DB_POSTGRES_URL")); System.out.println("DB_USERNAME: " + System.getenv("DB_USERNAME")); System.out.println("========================================="); }; } }
